#include<cstdio>
#include<cstring>
#include<vector>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=210,Mod=1e9+7;std::vector<int> G[N];
int n,l[N],r[N],L,R,dp[N][2],g[N][2],ans1,ans2,P[N],p,K,x[N],y[2][N];
inline void DN(int &x){x>=Mod?x-=Mod:0;} inline void UP(int &x){x<0?x+=Mod:0;}
inline int qpow(int a,int b=Mod-2){int r(1);for(;b;a=1ll*a*a%Mod,b>>=1)if(b&1)r=1ll*r*a%Mod;return r;}
inline int S(int x){return ((1ll*x*(x+1))>>1)%Mod;}
inline void dfs(int u=1,int fa=0)
{
	int ql=max(l[u],L),qr=min(r[u],R);if(ql>qr)ql=1,qr=0;
	int qlen=dp[u][0]=dp[u][1]=(qr-ql+1),wlen=S(qr)-S(ql-1);
	UP(wlen);g[u][0]=g[u][1]=wlen;
	for(int v:G[u])if(v!=fa)
	{
		dfs(v,u);
		dp[u][0]=(1ll*dp[u][1]*dp[v][1]+dp[u][0])%Mod;
		g[u][0]=(1ll*g[u][1]*dp[v][1]+1ll*g[v][1]*dp[u][1]+g[u][0])%Mod;
		dp[u][1]=(1ll*dp[v][1]*qlen+dp[u][1])%Mod;
		g[u][1]=(1ll*g[v][1]*qlen+1ll*dp[v][1]*wlen+g[u][1])%Mod;
	}
}
/*
dp[u][0] -->  the number of paths pass u
dp[u][1] -->  the number of paths end in u
g[u][0]  -->  the value of paths pass u
g[u][1]  -->  the value of paths end in u
*/
inline void CntG(){dfs();rep(1,n,i)DN(ans1+=dp[i][0]),DN(ans2+=g[i][0]);}
inline void CntI(){dfs();rep(1,n,i)UP(ans1-=dp[i][0]),UP(ans2-=g[i][0]);}

inline int Lag(int n,int *x,int *y,int X)
{
	int res=0;for(int i=0;i<n;++i)
	{
		int p=1,q=1;for(int j=0;j<n;++j)if(i!=j)p=1ll*p*(X-x[j])%Mod,q=1ll*q*(x[i]-x[j])%Mod;
		UP(p);UP(q);res=(1ll*p*qpow(q)%Mod*y[i]+res)%Mod;
	}
	return res;
}

int main()
{
	n=read();K=read();p=1;rep(1,n,i)
	{
		P[++p]=l[i]=read();P[++p]=r[i]=read();
		P[++p]=max(l[i]-K,0);P[++p]=max(r[i]-K,0);P[1]=max(P[1],r[i]+1); 
	}
	std::sort(P+1,P+p+1);p=std::unique(P+1,P+p+1)-P-1;
	rep(2,n,i){int x=read(),y=read();G[x].push_back(y);G[y].push_back(x);}
	for(int i=1;i<p;++i)
	{
		L=P[i];R=P[i]+K;int j=0;
		for(j=0;j<n+2&&P[i]+j!=P[i+1];++j,++R)
		{
			CntG();++L;CntI();
			x[j]=P[i]+j;y[0][j]=ans1;y[1][j]=ans2;
		}
		if(P[i]+j<P[i+1])
		{
			ans1=Lag(j,x,y[0],P[i+1]-1);
			ans2=Lag(j,x,y[1],P[i+1]-1);
		}
//		printf("%d :: %d %d\n",i,ans1,ans2);
	}
	printf("%d\n%d\n",ans1,ans2);return 0;
}
